  // Queue adapter deliveries to preserve notification ordering.
  // Each notification's adapters must complete before the next notification's
  // adapters start, preventing out-of-order delivery (e.g., "payment confirmed"
  // arriving before "order placed").
  this.deliveryQueue = this.deliveryQueue.then(async () => {
    for (const adapter of enabledAdapters) {
      const adapterRecipient = params.channelRecipients?.[adapter.name] ?? params.recipient;
      const adapterPayload = { ...notification, recipient: adapterRecipient };

      try {
        await adapter.send(adapterPayload);
        if (this.historyService) {
