  describe('notification ordering', () => {
    it('should deliver notifications to adapters in the order they were sent', async () => {
      const deliveryOrder: string[] = [];

      // Create an adapter that records delivery order with a variable delay
      // to simulate real-world async behavior where later calls could resolve first
      const trackingAdapter: NotificationAdapter = {
        name: 'tracking',
        async send(notification) {
          // Second notification gets a shorter delay — without ordering,
          // it would arrive first
          const delay = notification.subject.includes('Order Confirmation') ? 50 : 10;
          await new Promise((r) => setTimeout(r, delay));
          deliveryOrder.push(notification.subject);
        },
      };
      service.registerAdapter(trackingAdapter);

      // Send "order placed" notification
      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };
      await eventBus.emit(orderCreatedEvent);

      // Send "status changed" notification immediately after
      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      await service.flush();

      // Despite the first notification having a longer delay,
      // it should still be delivered first
      expect(deliveryOrder).toHaveLength(2);
      expect(deliveryOrder[0]).toContain('Order Confirmation');
      expect(deliveryOrder[1]).toContain('Order Update');
    });
  });
});

